import { defineComponentStyle } from "@yamada-ui/react"

export const flexStyle = defineComponentStyle({
  base: {
    display: "flex",
  },
})

export type FlexStyle = typeof flexStyle

import { page, render } from "#test/browser"
import { Flex } from "./flex"

describe("<Flex />", () => {
  test("sets `displayName` correctly", () => {
    expect(Flex.displayName).toBe("Flex")
  })

  test("sets `className` correctly", async () => {
    await render(<Flex>Flex</Flex>)

    const flex = page.getByText("Flex")
    await expect.element(flex).toHaveClass("ui-flex")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Flex>Flex</Flex>)

    const flex = page.getByText("Flex")
    expect(flex.element().tagName).toBe("DIV")
  })

  test("renders all the allowed shorthand style props", async () => {
    await render(
      <Flex
        align="stretch"
        basis="auto"
        direction="row"
        grow={1}
        justify="start"
        shrink={0}
        wrap="nowrap"
      >
        Flex
      </Flex>,
    )

    const flex = page.getByText("Flex")
    await expect.element(flex).toHaveStyle({
      alignItems: "stretch",
      flexBasis: "auto",
      flexDirection: "row",
      flexGrow: "1",
      flexShrink: "0",
      flexWrap: "nowrap",
      justifyContent: "start",
    })
  })
})

"use client"

import type { HTMLStyledProps } from "@yamada-ui/react"
import { styled } from "@yamada-ui/react"

export interface SpacerProps extends HTMLStyledProps {}

export const Spacer = styled("div", {
  name: "spacer",
  base: {
    alignSelf: "stretch",
    flex: 1,
    justifySelf: "stretch",
  },
})
